1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 1 / 10;
3	
4	const applyFirstInsuranceSurcharge = (premium: number): number =>
5	  premium + premium * FIRST_INSURANCE_SURCHARGE_RATE;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	const BLOCK_SIZE = 3;
18	const BLOCK_PREMIUM = 60;
19	
20	export const quote = (items: Array<{ type: string }>, customer: unknown, contractNumber: number): number => {
21	  const componentCounts: Record<string, number> = {};
22	  for (const item of items) {
23	    if (COMPONENT_TYPES.includes(item.type)) {
24	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
25	    }
26	  }
27	
28	  let totalPremium = 0;
29	
30	  for (const item of items) {
31	    if (COMPONENT_TYPES.includes(item.type) && componentCounts[item.type] === BLOCK_SIZE) {
32	      continue;
33	    }
34	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
35	    totalPremium += applyFirstInsuranceSurcharge(basePremium);
36	  }
37	
38	  for (const type of COMPONENT_TYPES) {
39	    if (componentCounts[type] === BLOCK_SIZE) {
40	      totalPremium += applyFirstInsuranceSurcharge(BLOCK_PREMIUM);
41	    }
42	  }
43	
44	  return Math.ceil(totalPremium) + PROCESSING_FEE;
45	};
